     1→//! Consensus analysis for multiblock datasets
     2→//!
     3→//! This module implements consensus analysis methods for multiblock data,
     4→//! particularly Consensus PCA (CPCA) which finds common principal components
     5→//! across multiple data blocks.
     6→//!
     7→//! # R Equivalents
     8→//! - `consensus_pca()` - Main consensus analysis function
     9→//! - `consensus_weights()` - Compute block weights for consensus
    10→//! - `consensus_scores()` - Extract consensus scores
    11→
    12→use crate::{
    13→    common_types::{Matrix, Vector},
    14→    errors::MultivariousError,
    15→    pca::pca::PCA,
    16→    preprocessing::{Preprocessor, steps::Pipeline},
    17→    projector::{BiProjector, Project, Reconstruct},
    18→    svd::SvdMethod,
    19→};
    20→use ndarray::{Array2, Axis};
    21→use std::collections::HashMap;
    22→
    23→/// Configuration for consensus analysis
    24→#[derive(Debug, Clone)]
    25→pub struct ConsensusConfig {
    26→    /// Number of consensus components to extract
    27→    pub n_components: Option<usize>,
    28→    /// SVD method to use
    29→    pub svd_method: SvdMethod,
    30→    /// Whether to center blocks before analysis
    31→    pub center: bool,
    32→    /// Whether to scale blocks before analysis
    33→    pub scale: bool,
    34→    /// Maximum iterations for consensus weight optimization
    35→    pub max_iterations: usize,
    36→    /// Convergence tolerance
    37→    pub tolerance: f64,
    38→}
    39→
    40→impl Default for ConsensusConfig {
    41→    fn default() -> Self {
    42→        Self {
    43→            n_components: None,
    44→            svd_method: SvdMethod::Full,
    45→            center: true,
    46→            scale: false,
    47→            max_iterations: 100,
    48→            tolerance: 1e-6,
    49→        }
    50→    }
    51→}
    52→
    53→/// Consensus projector for multiblock analysis
    54→///
    55→/// Implements Consensus PCA which finds common principal components
    56→/// across multiple data blocks by iteratively optimizing block weights
    57→/// to maximize consensus.
    58→#[derive(Debug, Clone)]
    59→pub struct ConsensusProjector {
    60→    /// Global consensus model (BiProjector)
    61→    global_model: BiProjector,
    62→    /// Block-specific projectors
    63→    block_models: HashMap<String, BiProjector>,
    64→    /// Block weights (normalized to sum to 1)
    65→    block_weights: HashMap<String, f64>,
    66→    /// Preprocessing pipelines for each block
    67→    preprocessors: HashMap<String, Pipeline>,
    68→    /// Configuration
    69→    config: ConsensusConfig,
    70→    /// Number of iterations used
    71→    iterations_used: usize,
    72→    /// Convergence history
    73→    convergence_history: Vec<f64>,
    74→}
    75→
    76→impl ConsensusProjector {
    77→    /// Create a new consensus projector from multiple data blocks
    78→    pub fn new(
    79→        blocks: &HashMap<String, Matrix>,
    80→        config: ConsensusConfig,
    81→    ) -> Result<Self, MultivariousError> {
    82→        // Validate inputs
    83→        if blocks.is_empty() {
    84→            return Err(MultivariousError::InvalidParameter(
    85→                "At least one block required for consensus analysis".to_string(),
    86→            ));
    87→        }
    88→
    89→        // Check that all blocks have the same number of rows
    90→        let n_rows = blocks.values().next().unwrap().nrows();
    91→        for (name, block) in blocks {
    92→            if block.nrows() != n_rows {
    93→                return Err(MultivariousError::DimensionMismatch(format!(
    94→                    "Block '{}' has {} rows, expected {}",
    95→                    name,
    96→                    block.nrows(),
    97→                    n_rows
    98→                )));
    99→            }
   100→        }
   101→
   102→        // Initialize equal weights
   103→        let n_blocks = blocks.len();
   104→        let initial_weight = 1.0 / n_blocks as f64;
   105→        let mut block_weights = HashMap::new();
   106→        for name in blocks.keys() {
   107→            block_weights.insert(name.clone(), initial_weight);
   108→        }
   109→
   110→        // Create preprocessors for each block
   111→        let mut preprocessors = HashMap::new();
   112→        for name in blocks.keys() {
   113→            let mut pipeline = Pipeline::new();
   114→            if config.center {
   115→                pipeline = pipeline.add(Box::new(crate::preprocessing::Center::new()));
   116→            }
   117→            if config.scale {
   118→                pipeline = pipeline.add(Box::new(crate::preprocessing::Scale::new()));
   119→            }
   120→            preprocessors.insert(name.clone(), pipeline);
   121→        }
   122→
   123→        // Create initial global model
   124→        let concatenated = concatenate_blocks(blocks, &block_weights)?;
   125→        let pca = PCA::fit(&concatenated, config.n_components, config.svd_method.clone())?;
   126→        let global_model = pca.as_bi_projector();
   127→
   128→        // Initialize with empty block models
   129→        let block_models = HashMap::new();
   130→
   131→        let mut projector = Self {
   132→            global_model,
   133→            block_models,
   134→            block_weights,
   135→            preprocessors,
   136→            config,
   137→            iterations_used: 0,
   138→            convergence_history: Vec::new(),
   139→        };
   140→
   141→        // Fit the consensus model
   142→        projector.fit(blocks)?;
   143→
   144→        Ok(projector)
   145→    }
   146→
   147→    /// Fit the consensus model by iteratively optimizing block weights
   148→    pub fn fit(&mut self, blocks: &HashMap<String, Matrix>) -> Result<(), MultivariousError> {
   149→        // Preprocess blocks
   150→        let mut preprocessed_blocks = HashMap::new();
   151→        for (name, block) in blocks {
   152→            let pipeline = self.preprocessors.get_mut(name).unwrap();
   153→            let preprocessed = pipeline.fit_transform(block)?;
   154→            preprocessed_blocks.insert(name.clone(), preprocessed);
   155→        }
   156→
   157→        // Iterative consensus optimization
   158→        let mut prev_weights = self.block_weights.clone();
   159→        
   160→        for iter in 0..self.config.max_iterations {
   161→            // Step 1: Update global model using current weights
   162→            let concatenated = concatenate_blocks(&preprocessed_blocks, &self.block_weights)?;
   163→            let pca = PCA::fit(&concatenated, self.config.n_components, self.config.svd_method.clone())?;
   164→            self.global_model = pca.as_bi_projector();
   165→
   166→            // Step 2: Fit block-specific models
   167→            self.block_models.clear();
   168→            for (name, block) in &preprocessed_blocks {
   169→                let block_pca = PCA::fit(block, self.config.n_components, self.config.svd_method.clone())?;
   170→                self.block_models.insert(name.clone(), block_pca.as_bi_projector());
   171→            }
   172→
   173→            // Step 3: Update block weights based on similarity to global model
   174→            let new_weights = self.compute_consensus_weights(&preprocessed_blocks)?;
   175→            
   176→            // Check convergence
   177→            let weight_change = compute_weight_change(&prev_weights, &new_weights);
   178→            self.convergence_history.push(weight_change);
   179→            
   180→            if weight_change < self.config.tolerance {
   181→                self.iterations_used = iter + 1;
   182→                self.block_weights = new_weights;
   183→                break;
   184→            }
   185→
   186→            prev_weights = new_weights.clone();
   187→            self.block_weights = new_weights;
   188→        }
   189→
   190→        if self.iterations_used == 0 {
   191→            self.iterations_used = self.config.max_iterations;
   192→        }
   193→
   194→        Ok(())
   195→    }
   196→
   197→    /// Compute consensus weights based on similarity to global model
   198→    fn compute_consensus_weights(
   199→        &self,
   200→        blocks: &HashMap<String, Matrix>,
   201→    ) -> Result<HashMap<String, f64>, MultivariousError> {
   202→        let mut weights = HashMap::new();
   203→        let mut total_similarity = 0.0;
   204→
   205→        // Compute similarity of each block's loadings to global loadings
   206→        let global_loadings = &self.global_model.v;
   207→        
   208→        for (name, _) in blocks {
   209→            if let Some(block_model) = self.block_models.get(name) {
   210→                let block_loadings = &block_model.v;
   211→                
   212→                // Compute RV coefficient (matrix correlation)
   213→                let similarity = compute_rv_coefficient(global_loadings, block_loadings)?;
   214→                weights.insert(name.clone(), similarity);
   215→                total_similarity += similarity;
   216→            }
   217→        }
   218→
   219→        // Normalize weights to sum to 1
   220→        if total_similarity > 0.0 {
   221→            for weight in weights.values_mut() {
   222→                *weight /= total_similarity;
   223→            }
   224→        }
   225→
   226→        Ok(weights)
   227→    }
   228→
   229→    /// Get consensus scores (from global model)
   230→    pub fn consensus_scores(&self) -> &Matrix {
   231→        self.global_model.scores()
   232→    }
   233→
   234→    /// Get consensus loadings (from global model)
   235→    pub fn consensus_loadings(&self) -> &Matrix {
   236→        self.global_model.components()
   237→    }
   238→
   239→    /// Get block-specific scores
   240→    pub fn block_scores(&self, block_name: &str) -> Option<&Matrix> {
   241→        self.block_models.get(block_name).map(|m| m.scores())
   242→    }
   243→
   244→    /// Get block weights
   245→    pub fn block_weights(&self) -> &HashMap<String, f64> {
   246→        &self.block_weights
   247→    }
   248→
   249→    /// Get number of iterations used
   250→    pub fn iterations_used(&self) -> usize {
   251→        self.iterations_used
   252→    }
   253→
   254→    /// Get convergence history
   255→    pub fn convergence_history(&self) -> &[f64] {
   256→        &self.convergence_history
   257→    }
   258→
   259→    /// Compute cross-block correlations for a given component
   260→    pub fn cross_block_correlations(&self, component: usize) -> Result<Matrix, MultivariousError> {
   261→        let block_names: Vec<_> = self.block_models.keys().cloned().collect();
   262→        let n_blocks = block_names.len();
   263→        
   264→        if n_blocks == 0 {
   265→            return Err(MultivariousError::InvalidParameter(
   266→                "No block models available".to_string(),
   267→            ));
   268→        }
   269→        
   270→        // Create correlation matrix
   271→        let mut corr_matrix = Array2::zeros((n_blocks, n_blocks));
   272→        
   273→        for (i, name_i) in block_names.iter().enumerate() {
   274→            for (j, name_j) in block_names.iter().enumerate() {
   275→                if i <= j {
   276→                    let scores_i = self.block_models.get(name_i).unwrap().scores();
   277→                    let scores_j = self.block_models.get(name_j).unwrap().scores();
   278→                    
   279→                    // Check component exists
   280→                    if component >= scores_i.ncols() || component >= scores_j.ncols() {
   281→                        return Err(MultivariousError::InvalidComponentCount(
   282→                            format!("Component {} not available", component),
   283→                        ));
   284→                    }
   285→                    
   286→                    // Extract component scores
   287→                    let comp_i = scores_i.column(component);
   288→                    let comp_j = scores_j.column(component);
   289→                    
   290→                    // Compute correlation
   291→                    let corr = compute_correlation(&comp_i.to_owned(), &comp_j.to_owned())?;
   292→                    corr_matrix[[i, j]] = corr;
   293→                    corr_matrix[[j, i]] = corr;  // Symmetric
   294→                }
   295→            }
   296→        }
   297→        
   298→        Ok(corr_matrix)
   299→    }
   300→
   301→    /// Compute consensus analysis result with full statistics
   302→    pub fn compute_consensus_result(&self) -> Result<ConsensusResult, MultivariousError> {
   303→        let n_components = self.global_model.n_components();
   304→        let mut consensus_stats = Vec::new();
   305→        
   306→        // Compute cross-correlations for first component (for result)
   307→        let cross_correlations = self.cross_block_correlations(0)?;
   308→        
   309→        // Compute statistics for each component
   310→        for comp in 0..n_components {
   311→            let corr_matrix = self.cross_block_correlations(comp)?;
   312→            
   313→            // Extract upper triangle (excluding diagonal)
   314→            let mut correlations = Vec::new();
   315→            for i in 0..corr_matrix.nrows() {
   316→                for j in (i+1)..corr_matrix.ncols() {
   317→                    correlations.push(corr_matrix[[i, j]].abs());
   318→                }
   319→            }
   320→            
   321→            let mean_corr = if !correlations.is_empty() {
   322→                correlations.iter().sum::<f64>() / correlations.len() as f64
   323→            } else {
   324→                1.0  // Single block case
   325→            };
   326→            
   327→            let std_corr = if correlations.len() > 1 {
   328→                let variance = correlations.iter()
   329→                    .map(|&x| (x - mean_corr).powi(2))
   330→                    .sum::<f64>() / (correlations.len() - 1) as f64;
   331→                variance.sqrt()
   332→            } else {
   333→                0.0
   334→            };
   335→            
   336→            let min_corr = correlations.iter().cloned().fold(1.0, f64::min);
   337→            let max_corr = correlations.iter().cloned().fold(0.0, f64::max);
   338→            
   339→            // Get variance explained from global model
   340→            let var_explained = self.global_model.sdev[comp].powi(2);
   341→            
   342→            consensus_stats.push(ConsensusStatistic {
   343→                component: comp,
   344→                variance_explained: var_explained,
   345→                mean_correlation: mean_corr,
   346→                std_correlation: std_corr,
   347→                min_correlation: min_corr,
   348→                max_correlation: max_corr,
   349→            });
   350→        }
   351→        
   352→        Ok(ConsensusResult {
   353→            projector: self.clone(),
   354→            cross_correlations,
   355→            consensus_stats,
   356→        })
   357→    }
   358→}
   359→
   360→/// Compute Pearson correlation between two vectors
   361→fn compute_correlation(x: &Vector, y: &Vector) -> Result<f64, MultivariousError> {
   362→    if x.len() != y.len() {
   363→        return Err(MultivariousError::DimensionMismatch(
   364→            "Vectors must have same length for correlation".to_string(),
   365→        ));
   366→    }
   367→    
   368→    let n = x.len() as f64;
   369→    if n <= 1.0 {
   370→        return Ok(1.0);
   371→    }
   372→    
   373→    let mean_x = x.sum() / n;
   374→    let mean_y = y.sum() / n;
   375→    
   376→    let mut cov = 0.0;
   377→    let mut var_x = 0.0;
   378→    let mut var_y = 0.0;
   379→    
   380→    for i in 0..x.len() {
   381→        let dx = x[i] - mean_x;
   382→        let dy = y[i] - mean_y;
   383→        cov += dx * dy;
   384→        var_x += dx * dx;
   385→        var_y += dy * dy;
   386→    }
   387→    
   388→    let denom = (var_x * var_y).sqrt();
   389→    if denom > 0.0 {
   390→        Ok(cov / denom)
   391→    } else {
   392→        Ok(0.0)
   393→    }
   394→}
   395→
   396→/// Concatenate blocks with optional weighting
   397→fn concatenate_blocks(
   398→    blocks: &HashMap<String, Matrix>,
   399→    weights: &HashMap<String, f64>,
   400→) -> Result<Matrix, MultivariousError> {
   401→    let mut columns = Vec::new();
   402→    
   403→    // Sort blocks by name for consistent ordering
   404→    let mut block_names: Vec<_> = blocks.keys().cloned().collect();
   405→    block_names.sort();
   406→
   407→    for name in block_names {
   408→        if let Some(block) = blocks.get(&name) {
   409→            let weight = weights.get(&name).unwrap_or(&1.0);
   410→            
   411→            // Apply square root of weight to columns (so that squared values give the weight)
   412→            let weighted_block = block * weight.sqrt();
   413→            
   414→            for col in weighted_block.axis_iter(Axis(1)) {
   415→                columns.push(col.to_owned());
   416→            }
   417→        }
   418→    }
   419→
   420→    if columns.is_empty() {
   421→        return Err(MultivariousError::InvalidParameter(
   422→            "No columns to concatenate".to_string(),
   423→        ));
   424→    }
   425→
   426→    // Stack columns horizontally
   427→    let n_rows = columns[0].len();
   428→    let n_cols = columns.len();
   429→    let mut result = Array2::zeros((n_rows, n_cols));
   430→    
   431→    for (i, col) in columns.into_iter().enumerate() {
   432→        result.column_mut(i).assign(&col);
   433→    }
   434→
   435→    Ok(result)
   436→}
   437→
   438→/// Compute RV coefficient between two matrices (matrix correlation)
   439→fn compute_rv_coefficient(x: &Matrix, y: &Matrix) -> Result<f64, MultivariousError> {
   440→    if x.nrows() != y.nrows() {
   441→        return Err(MultivariousError::DimensionMismatch(
   442→            "Matrices must have same number of rows for RV coefficient".to_string(),
   443→        ));
   444→    }
   445→
   446→    // RV = trace(X'X * Y'Y) / sqrt(trace((X'X)^2) * trace((Y'Y)^2))
   447→    let xx = x.t().dot(x);
   448→    let yy = y.t().dot(y);
   449→    let xy = xx.dot(&yy);
   450→    
   451→    let numerator = xy.diag().sum();
   452→    let xx_squared = xx.dot(&xx);
   453→    let yy_squared = yy.dot(&yy);
   454→    
   455→    let denominator = (xx_squared.diag().sum() * yy_squared.diag().sum()).sqrt();
   456→    
   457→    if denominator > 0.0 {
   458→        Ok(numerator / denominator)
   459→    } else {
   460→        Ok(0.0)
   461→    }
   462→}
   463→
   464→/// Compute change in weights between iterations
   465→fn compute_weight_change(
   466→    old_weights: &HashMap<String, f64>,
   467→    new_weights: &HashMap<String, f64>,
   468→) -> f64 {
   469→    let mut total_change = 0.0;
   470→    
   471→    for (name, &new_weight) in new_weights {
   472→        if let Some(&old_weight) = old_weights.get(name) {
   473→            total_change += (new_weight - old_weight).abs();
   474→        }
   475→    }
   476→    
   477→    total_change
   478→}
