   480→impl Project for ConsensusProjector {
   481→    fn project(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
   482→        self.global_model.project(data)
   483→    }
   484→}
   485→
   486→impl Reconstruct for ConsensusProjector {
   487→    fn reconstruct(&self, scores: &Matrix) -> Result<Matrix, MultivariousError> {
   488→        self.global_model.reconstruct(scores)
   489→    }
   490→}
