   492→/// Result of consensus analysis
   493→#[derive(Debug, Clone)]
   494→pub struct ConsensusResult {
   495→    /// The consensus projector
   496→    pub projector: ConsensusProjector,
   497→    /// Cross-block correlation matrix
   498→    pub cross_correlations: Matrix,
   499→    /// Consensus statistics per component
   500→    pub consensus_stats: Vec<ConsensusStatistic>,
   501→}
   502→
   503→/// Statistics for a single consensus component
   504→#[derive(Debug, Clone)]
   505→pub struct ConsensusStatistic {
   506→    /// Component index
   507→    pub component: usize,
   508→    /// Variance explained by this component
   509→    pub variance_explained: f64,
   510→    /// Mean absolute correlation across blocks
   511→    pub mean_correlation: f64,
   512→    /// Standard deviation of correlations
   513→    pub std_correlation: f64,
   514→    /// Minimum correlation across blocks
   515→    pub min_correlation: f64,
   516→    /// Maximum correlation across blocks
   517→    pub max_correlation: f64,
   518→}
