   556→    #[test]
   557→    fn test_concatenate_blocks() {
   558→        let mut blocks = HashMap::new();
   559→        blocks.insert("a".to_string(), array![[1.0, 2.0], [3.0, 4.0]]);
   560→        blocks.insert("b".to_string(), array![[5.0], [6.0]]);
