   570→    #[test]
   571→    fn test_weighted_concatenation() {
   572→        let mut blocks = HashMap::new();
   573→        blocks.insert("a".to_string(), array![[2.0], [2.0]]);
   574→        blocks.insert("b".to_string(), array![[4.0], [4.0]]);
   575→        
   576→        let mut weights = HashMap::new();
   577→        weights.insert("a".to_string(), 0.25);  // sqrt(0.25) = 0.5
   578→        weights.insert("b".to_string(), 0.25);  // sqrt(0.25) = 0.5
   579→        
   580→        let concatenated = concatenate_blocks(&blocks, &weights).unwrap();
   581→        // Values should be scaled by sqrt(weight)
   582→        assert!((concatenated[[0, 0]] - 1.0).abs() < 1e-10);
   583→        assert!((concatenated[[0, 1]] - 2.0).abs() < 1e-10);
