   586→    #[test]
   587→    fn test_consensus_convergence() {
   588→        // Create blocks with similar structure
   589→        let mut blocks = HashMap::new();
   590→        let block1 = array![
   591→            [1.0, 0.1, 0.2],
   592→            [0.1, 1.0, 0.15],
   593→            [0.2, 0.15, 1.0],
   594→            [0.3, 0.25, 0.9]
   595→        ];
   596→        let block2 = array![
   597→            [0.9, 0.15],
   598→            [0.12, 0.95],
   599→            [0.18, 0.2],
   600→            [0.28, 0.3]
   601→        ];
