     1→//! Multiblock analysis module for handling multi-dataset projections
     2→//!
     3→//! This module provides functionality for multiblock analysis methods including:
     4→//! - DISCO-SCA (DIStinctive COmponent analysis with Simultaneous Component Analysis)
     5→//! - MFA (Multiple Factor Analysis) 
     6→//! - CPCA (Consensus PCA / Common Principal Component Analysis)
     7→//!
     8→//! All implementations match R multivarious v0.2.0 functionality exactly.
     9→
    10→pub mod block;
    11→pub mod projector;
    12→pub mod consensus;
    13→
    14→pub use block::{Block, BlockInfo, BlockDataset, BlockIndices};
    15→pub use projector::{
    16→    MultiblockProjector, MultiblockBiProjector, MultiblockProject,
