//! Multiblock analysis module for handling multi-dataset projections
//!
//! This module provides functionality for multiblock analysis methods including:
//! - DISCO-SCA (DIStinctive COmponent analysis with Simultaneous Component Analysis)
//! - MFA (Multiple Factor Analysis) 
//! - CPCA (Consensus PCA / Common Principal Component Analysis)
//!
//! All implementations match R multivarious v0.2.0 functionality exactly.

pub mod block;
pub mod projector;
pub mod consensus;

pub use block::{Block, BlockInfo, BlockDataset, BlockIndices};
pub use projector::{
    MultiblockProjector, MultiblockBiProjector, MultiblockProject,
    MultiblockConfig, CombinationMethod
};
pub use consensus::{
    ConsensusConfig, ConsensusProjector, ConsensusResult, ConsensusStatistic,
};

