            [0.3, 0.25, 0.9]
        ];
        let block2 = array![
            [0.9, 0.15],
            [0.12, 0.95],
            [0.18, 0.2],
            [0.28, 0.3]
        ];

        blocks.insert("block1".to_string(), block1);
        blocks.insert("block2".to_string(), block2);

        let config = ConsensusConfig {
            n_components: Some(2),
            max_iterations: 10,
            ..Default::default()
        };

        let projector = ConsensusProjector::new(&blocks, config).unwrap();

        // Check convergence
        assert!(projector.iterations_used() <= 10);
        let history = projector.convergence_history();
        if history.len() > 1 {
            // Convergence should be decreasing
            for i in 1..history.len() {
                assert!(history[i] <= history[i-1] + 1e-10);
            }
        }
    }

    #[test]
    fn test_consensus_scores_shape() {
