    fn test_pca_correlation_mode() {
        // Data with different scales
        let data = array![
            [1.0, 100.0],
            [2.0, 200.0],
            [3.0, 300.0],
            [4.0, 400.0],
        ];

        let mut pca_cov = PcaBuilder::new()
            .use_correlation(false)
            .n_components(1)
            .build();

        let mut pca_corr = PcaBuilder::new()
            .use_correlation(true)
            .n_components(1)
            .build();

        pca_cov.fit(&data).unwrap();
        pca_corr.fit(&data).unwrap();

        // The components should be different due to scaling
        let comp_cov = pca_cov.components().unwrap();
        let comp_corr = pca_corr.components().unwrap();

        // In covariance mode, the second feature dominates
        assert!(comp_cov[[0, 1]].abs() > comp_cov[[0, 0]].abs());

        // In correlation mode, features are standardized first
        assert!((comp_corr[[0, 0]].abs() - comp_corr[[0, 1]].abs()).abs() < 0.1);
    }

