    #[test]
    fn test_variance_methods() {
        // Create data with clear variance structure
        let data = array![
            [1.0, 0.0, 0.0, 0.0],
            [2.0, 0.1, 0.0, 0.0],
            [3.0, 0.0, 0.1, 0.0],
            [4.0, 0.1, 0.0, 0.1],
            [5.0, 0.0, 0.1, 0.0],
        ];

        let mut pca = PcaBuilder::new()
            .n_components(4)
            .build();

        pca.fit(&data).unwrap();

        // Test explained variance
        let explained_var = pca.explained_variance().unwrap();
        assert_eq!(explained_var.len(), 4);
        assert!(explained_var[0] > explained_var[1]); // First component should have most variance

        // Test n_components_for_variance
        let n_comps = pca.n_components_for_variance(0.95).unwrap();
        assert!(n_comps >= 1 && n_comps <= 4);

        // Test variance explained by subset
        let var_subset = pca.variance_explained_by_components(&[0, 1]).unwrap();
        assert!(var_subset > 0.0 && var_subset <= 1.0);
        assert!(var_subset <= pca.total_variance_explained());

        // Test standard deviations
        let sdevs = pca.standard_deviations();
        assert_eq!(sdevs.len(), 4);
        for i in 0..sdevs.len() {
            assert!((sdevs[i] * sdevs[i] - explained_var[i]).abs() < 1e-10);
        }

        // Test total variance
        assert!(pca.total_variance() > 0.0);
    }

    #[test]
    fn test_kaiser_criterion() {
        // Create standardized data for correlation PCA
        let data = array![
            [1.0, 2.0, 3.0, 0.1],
            [2.0, 4.0, 6.0, 0.2],
            [3.0, 6.0, 9.0, 0.1],
            [4.0, 8.0, 12.0, 0.2],
            [5.0, 10.0, 15.0, 0.1],
        ];

        let mut pca = PcaBuilder::new()
            .use_correlation(true) // Required for Kaiser criterion
            .build();

        pca.fit(&data).unwrap();

        // Test Kaiser criterion
        let n_kaiser = pca.kaiser_criterion().unwrap();
        assert!(n_kaiser >= 1);

        // Kaiser criterion should fail for covariance PCA
        let mut pca_cov = PcaBuilder::new()
            .use_correlation(false)
            .build();
        pca_cov.fit(&data).unwrap();
        assert!(pca_cov.kaiser_criterion().is_err());
    }

    #[test]
    fn test_scree_and_elbow() {
        // Create data with clear elbow
        let mut data = Matrix::zeros((20, 5));
        // First two components have high variance
        for i in 0..20 {
            data[[i, 0]] = i as f64 * 2.0;
            data[[i, 1]] = i as f64 * 1.5;
            // Rest have low variance
            data[[i, 2]] = (i % 2) as f64 * 0.1;
            data[[i, 3]] = (i % 3) as f64 * 0.1;
            data[[i, 4]] = (i % 4) as f64 * 0.1;
        }

        let mut pca = PcaBuilder::new().build();
        pca.fit(&data).unwrap();

        // Test scree values
        let scree = pca.scree_values().unwrap();
        assert_eq!(scree.len(), 4); // n_components - 1
        assert!(scree[0] > scree[1]); // Biggest drop should be first

        // Test elbow point
        let elbow = pca.elbow_point().unwrap();
        assert!(elbow >= 2 && elbow <= 3); // Should identify the elbow around component 2-3
    }

    #[test]
    fn test_variance_methods_errors() {
        let mut pca = PcaBuilder::new().build();

        // Not fitted errors
        assert!(pca.explained_variance().is_err());
        assert!(pca.n_components_for_variance(0.95).is_err());
        assert!(pca.kaiser_criterion().is_err());
        assert!(pca.scree_values().is_err());
        assert!(pca.elbow_point().is_err());
        assert!(pca.variance_explained_by_components(&[0]).is_err());

        // Fit with minimal data
        let data = array![[1.0], [2.0]];
        pca.fit(&data).unwrap();

        // Test invalid variance ratio
        assert!(pca.n_components_for_variance(-0.1).is_err());
        assert!(pca.n_components_for_variance(1.1).is_err());

        // Test invalid component indices
        assert!(pca.variance_explained_by_components(&[5]).is_err());
    }

    #[test]
    fn test_truncate() {
        let data = array![
            [1.0, 2.0, 3.0, 4.0],
            [2.0, 3.0, 4.0, 5.0],
            [3.0, 4.0, 5.0, 6.0],
            [4.0, 5.0, 6.0, 7.0],
            [5.0, 6.0, 7.0, 8.0],
        ];

        let mut pca = PcaBuilder::new()
            .n_components(4)
            .build();

        pca.fit(&data).unwrap();
        assert_eq!(pca.n_components(), 4);

        // Truncate to 2 components
        pca.truncate(2).unwrap();
        assert_eq!(pca.n_components(), 2);
        assert_eq!(pca.explained_variance_ratio().len(), 2);
        assert_eq!(pca.singular_values().len(), 2);

        // Test invalid truncation
        assert!(pca.truncate(0).is_err());
        assert!(pca.truncate(5).is_err());

        // Truncate to same number should be no-op
        assert!(pca.truncate(2).is_ok());
        assert_eq!(pca.n_components(), 2);
    }

    #[test]
    fn test_auto_select_components() {
        let data = array![
            [1.0, 0.0, 0.0],
            [2.0, 0.1, 0.0],
            [3.0, 0.0, 0.1],
            [4.0, 0.1, 0.0],
            [5.0, 0.0, 0.1],
        ];

        // Test variance threshold
        let mut pca = PcaBuilder::new().build();
        pca.fit(&data).unwrap();
        let n_selected = pca.auto_select_components(ComponentSelectionCriterion::VarianceThreshold(0.9)).unwrap();
        assert!(n_selected >= 1 && n_selected <= 3);

        // Test fixed number
        let mut pca2 = PcaBuilder::new().build();
        pca2.fit(&data).unwrap();
        let n_fixed = pca2.auto_select_components(ComponentSelectionCriterion::FixedNumber(2)).unwrap();
        assert_eq!(n_fixed, 2);
        assert_eq!(pca2.n_components(), 2);
    }

    #[test]
    fn test_outlier_detection() {
        let data = array![
            [1.0, 1.0],
            [2.0, 2.0],
            [3.0, 3.0],
            [10.0, 10.0], // Outlier
        ];

        let mut pca = PcaBuilder::new().build();
        pca.fit(&data).unwrap();

        // Test Hotelling T²
        let t2 = pca.hotelling_t2(&data).unwrap();
        assert_eq!(t2.len(), 4);
        // Last sample should have highest T² value
        assert!(t2[3] > t2[0]);
        assert!(t2[3] > t2[1]);
        assert!(t2[3] > t2[2]);

        // Test Q-residuals
        let q = pca.q_residuals(&data).unwrap();
        assert_eq!(q.len(), 4);
        // For perfect linear data, residuals should be very small
        for i in 0..3 {
            assert!(q[i] < 0.1);
        }
    }

    #[test]
    fn test_contributions() {
        let data = array![
            [1.0, 2.0, 3.0],
            [2.0, 4.0, 6.0],
            [3.0, 6.0, 9.0],
            [4.0, 8.0, 12.0],
        ];

        let mut pca = PcaBuilder::new().build();
        pca.fit(&data).unwrap();

        // Test variable contributions
        let var_contrib = pca.variable_contributions().unwrap();
        assert_eq!(var_contrib.shape(), &[3, 3]); // n_components x n_features

        // Each row should sum to approximately 1 (contributions to each PC)
        for i in 0..3 {
            let row_sum: f64 = var_contrib.row(i).sum();
            assert!((row_sum - 1.0).abs() < 0.01);
        }

        // Test sample contributions
        let sample_contrib = pca.sample_contributions(&data).unwrap();
        assert_eq!(sample_contrib.shape(), &[4, 3]); // n_samples x n_components

        // All contributions should be non-negative
        for val in sample_contrib.iter() {
            assert!(*val >= 0.0);
        }
    }

